3_real_world_example.code:
// V8 optimizes this: consistent object shape
const points = [];
for (let i = 0; i < 1_000_000; i++) {
  points.push({ x: i, y: i * 2 }); // Same shape every time → V8 can inline
}

// V8 struggles with this: shape changes (de-optimises)
const mixed = { name: 'Alice' };
mixed.age = 30;    // New property added after creation
mixed.score = 95;  // Another new property → hidden class changes force re-analysis

6_edge_case.code:
function addNumbers(a, b) {
  return a + b; // V8 optimizes for numbers after a few calls
}

// Warm up with numbers (V8 inlines and JIT-compiles)
for (let i = 0; i < 10000; i++) addNumbers(i, i + 1);

// Now pass a string — forces V8 to de-optimize this function!
console.log(addNumbers('hello', ' world')); // 'hello world'
// addNumbers will be re-analysed at slower bytecode speed
